 var labelKeys = mlContext.Data.LoadFromEnumerable(new[]
 {
     new { Churned = "Yes", Label = true },
     new { Churned = "No", Label = false },
 });

 var pipeline = mlContext.Transforms.Conversion.MapValue("Label", labelKeys, labelKeys.Schema["Churned"], labelKeys.Schema["Label"],
         inputColumnName: nameof(ChurnInput.Churned))
     .Append(mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", nameof(ChurnInput.Region)))
     .Append(mlContext.Transforms.Concatenate("Features", nameof(ChurnInput.Age), nameof(ChurnInput.Income),
         "RegionEncoded", nameof(ChurnInput.PurchaseHistory)))
     .Append(mlContext.Transforms.NormalizeMinMax("Features"))
     .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression(
         labelColumnName: "Label", featureColumnName: "Features"));

 var rowCount = (int)mlContext.Data.CreateEnumerable<ChurnInput>(dataView, reuseRowObject: false).LongCount();

 if (rowCount >= 20)
 {
     // Enough data for a meaningful train/test split
     var split = mlContext.Data.TrainTestSplit(dataView, testFraction: 0.2);
     var model = pipeline.Fit(split.TrainSet);
     var predictions = model.Transform(split.TestSet);
     var metrics = mlContext.BinaryClassification.Evaluate(predictions, labelColumnName: "Label");
     Console.WriteLine($"Model metrics — AUC: {metrics.AreaUnderRocCurve:F4}, F1: {metrics.F1Score:F4}, Accuracy: {metrics.Accuracy:F4}");
     mlContext.Model.Save(model, dataView.Schema, modelPath);
 }
 else
 {
     // Too few rows for a reliable split — train on all data
     Console.WriteLine($"Warning: Only {rowCount} rows — training on all data. Add more rows for proper train/test evaluation.");
     var model = pipeline.Fit(dataView);
     mlContext.Model.Save(model, dataView.Schema, modelPath);
 }

 // Register the pooled prediction engine (thread-safe for web apps)
 builder.Services.AddPredictionEnginePool<ChurnInput, ChurnOutput>()
     .FromFile(modelPath);

 var app = builder.Build();

 app.MapGet("/", () => "Churn Predictor API — POST /predict with { age, income, region, purchaseHistory }");

 app.MapPost("/predict", (PredictionEnginePool<ChurnInput, ChurnOutput> pool, ChurnRequest req) =>
 {
     var input = new ChurnInput
     {
         Age = req.Age,
         Income = req.Income,
         Region = req.Region,
         PurchaseHistory = req.PurchaseHistory,
     };
     var result = pool.Predict(input);
     return Results.Ok(new
     {
         WillChurn = result.PredictedLabel,
         Confidence = result.Probability,
     });
 });

 app.Run();

 public record ChurnRequest(float Age, float Income, string Region, float PurchaseHistory);

 public class ChurnInput
 {
     [LoadColumn(0)] public float Age { get; set; }
     [LoadColumn(1)] public float Income { get; set; }
     [LoadColumn(2)] public string Region { get; set; } = string.Empty;
     [LoadColumn(3)] public float PurchaseHistory { get; set; }
     [LoadColumn(4)] public string Churned { get; set; } = string.Empty;
 }

 public class ChurnOutput
 {
     [ColumnName("PredictedLabel")] public bool PredictedLabel { get; set; }
     public float Probability { get; set; }
     public float Score { get; set; }
 }

